"""Emission compliance tests for config (auto-generated by pact)."""

from config.config import Config


class TestEmissionCompliance:
    """Verify config emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_default_config_emits_events(self):
        """Method default_config emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = Config(event_handler=handler)
        try:
            obj.default_config()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for default_config'
        assert len(completed) >= 1, 'No completed/error event for default_config'
        assert invoked[0].get("pact_key") == "PACT:config:default_config"
        assert isinstance(invoked[0].get("input_classification"), list)

